SELECT first_name, last_name, date_of_death
FROM deceased
ORDER BY date_of_death DESC;

SELECT first_name
FROM deceased
WHERE cause_of_death = 'Heart Disease';

SELECT COUNT(burial_id) AS total_burials
FROM burials
WHERE strftime('%Y', interment_date) = '2023';

SELECT plot_number
FROM plots
ORDER BY plot_number ASC;

SELECT COUNT(deceased_id) AS deceased_count
FROM deceased
WHERE strftime('%Y', date_of_death) = '2023';

SELECT section_name, section_size
FROM sections
ORDER BY section_size DESC;

SELECT COUNT(burial_id) AS burial_count
FROM burials
WHERE section_id = 1;
